import "./notificationList.css";
import { DataGrid } from "@material-ui/data-grid";
import { useDispatch, useSelector } from 'react-redux';
import notificationAdapter, { getAllNotifications, notificationRead } from "../../redux/notificationRedux";
import { getNotifications, updatedNotification } from "../../redux/apiCalls";
import { useEffect } from "react";


const NotificationList = () => {
    const dispatch = useDispatch();
    const notifications = useSelector(state => state.notification.notifications);
    console.log(notifications)

    useEffect(() => {
        getNotifications(dispatch)
    }, [dispatch]);

    const handleMarkAsRead = (_id, notificationToUpdate) => {
        updatedNotification(_id, notificationToUpdate, dispatch);
    };

  return (
    <div className='notificationsContainer'>
        <h1 className="notificationsTitle">Notifications</h1>
        {notifications.map(notification => {
            return (
                <div className="notificationBlock">
                    {notification.message}
                </div>
            )
        })}
    </div>
  )
}

export default NotificationList
